Example:
// src/lib.rs
mod users;      // loads src/users.rs or src/users/mod.rs
mod orders;     // loads src/orders.rs or src/orders/mod.rs
pub mod config; // public module

// New style (preferred):
// src/users.rs   (module file)
// src/users/     (submodules if needed)

// Default: private to parent module
fn helper() {}

// Public API:
pub fn process() {}

// Crate-internal only:
pub(crate) struct InternalConfig {}

// Visible to parent module only:
pub(super) fn parent_helper() {}

// Preferred (new style):
// src/
//   lib.rs
//   users.rs          (mod users)
//   users/
//     service.rs      (mod users::service)
//     repository.rs   (mod users::repository)

// Legacy style (still valid):
// src/
//   lib.rs
//   users/
//     mod.rs          (mod users)
//     service.rs

// src/lib.rs
mod domain;
mod handlers;
mod errors;

// Clean public API:
pub use domain::User;
pub use domain::Order;
pub use errors::AppError;

// Users see: mycrate::User, mycrate::AppError
// Not: mycrate::domain::models::user::User

// src/prelude.rs
pub use crate::errors::{AppError, Result};
pub use crate::domain::{User, Order};
pub use crate::traits::{Repository, Service};

// Usage in other files:
use crate::prelude::*;

use std::collections::HashMap;
use std::sync::Arc;

use serde::{Deserialize, Serialize};
use tokio::sync::mpsc;

use crate::models::User;
use crate::errors::AppError;

#[cfg(target_os = "linux")]
fn get_memory_info() -> usize {
    // Linux-specific implementation
}

#[cfg(target_os = "macos")]
fn get_memory_info() -> usize {
    // macOS-specific implementation
}

#[cfg(test)]
mod tests {
    // only compiled during tests
}

// src/lib.rs
pub mod core;
pub mod config;
pub use core::Engine;

// src/main.rs
use myapp::{Engine, config::Config};

fn main() -> anyhow::Result<()> {
    let cfg = Config::from_env()?;
    let engine = Engine::new(cfg);
    engine.run()
}

// build.rs
fn main() {
    // Set cfg flags:
    println!("cargo:rerun-if-changed=proto/");

    // Generate code from protobuf:
    tonic_build::compile_protos("proto/service.proto").unwrap();

    // Embed version info:
    println!("cargo:rustc-env=GIT_HASH={}",
        String::from_utf8_lossy(&std::process::Command::new("git")
            .args(["rev-parse", "--short", "HEAD"])
            .output().unwrap().stdout).trim());
}

# Workspace member:
[dependencies]
shared = { path = "../shared" }

# With version (for publishing):
[dependencies]
shared = { version = "0.1", path = "../shared" }

# Git dependency:
[dependencies]
mylib = { git = "https://github.com/org/mylib", branch = "main" }
